(()=>{function a(){let e=window.location.pathname.split("/").pop()||"index.html";document.querySelectorAll(".nav-link").forEach(t=>{let n=t.getAttribute("href")||"";(n===e||e===""&&n==="index.html")&&(t.setAttribute("aria-current","page"),t.classList.add("nav-link--active"))})}document.addEventListener("DOMContentLoaded",a);})();
